1	import { mkdirSync, writeFileSync } from "node:fs";
2	import path from "node:path";
3	import { ERROR_CODES } from "./constants.js";
4	import { isoHoursAgo, isoMinutesAgo } from "./clock.js";
5	import type { SessionInspectView, SessionRecord, SessionUpdateData } from "./db.js";
6	import { diagnoseClaudeFailure, errorPayload, SPEC_ERROR_MESSAGES, type ErrorPayload } from "./errors.js";
7	import { createInternalSessionId } from "./ids.js";
8	import { type LockProvider } from "./locks.js";
9	import { findBestSessionMatch, normalizeTopicKey } from "./matching.js";
10	import { buildBootstrapContext, buildConsultPrompt, buildSessionContext } from "./prompt.js";
11	import type { RouterRuntime } from "./runtime.js";
12	import { parseSessionUpdate } from "./sessionUpdate.js";
13	
14	export interface ClaudeConsultInput {
15	  projectId: string;
16	  sessionId?: string | null;
17	  topicHint: string;
18	  trigger: string;
19	  task: string;
20	  relevantCode: string;
21	  question: string;
22	}
23	
24	export interface ConsultSuccess {
25	  session_id: string;
26	  claude_session_id: string;
27	  answer: string;
28	  routing: {
29	    match_score: number;
30	    match_reason: string;
31	    was_new_session: boolean;
32	    was_orphan_recovery: boolean;
33	  };
34	  session_update?: SessionUpdateData;
35	  warning?: {
36	    code: typeof ERROR_CODES.SESSION_UPDATE_PARSE_FAILED;
37	    message: string;
38	  };
39	  diagnostics?: {
40	    token_anomaly?: TokenAnomalyDiagnostic;
41	  };
42	}
43	
44	export type ConsultResult = ConsultSuccess | ErrorPayload;
45	
46	export class ConsultService {
47	  constructor(
48	    private readonly runtime: RouterRuntime,
49	    private readonly locks: LockProvider
50	  ) {}
51	
52	  async consult(input: ClaudeConsultInput): Promise<ConsultResult> {
53	    if (this.runtime.degradedMode) {
54	      const diagnosis = diagnoseClaudeFailure(this.runtime.degradedReason);
55	      return errorPayload(ERROR_CODES.CLAUDE_INCOMPATIBLE, SPEC_ERROR_MESSAGES[ERROR_CODES.CLAUDE_INCOMPATIBLE], {
56	        detected_version: this.runtime.detectedClaudeVersion,
57	        tested_versions: this.runtime.testedClaudeVersions,
58	        reason: diagnosis.reason,
59	        category: diagnosis.category,
60	        operator_action: diagnosis.operator_action
61	      });
62	    }
63	
64	    return this.locks.withLock(`cost:${input.projectId}`, async () => this.consultWithCostLock(input));
65	  }
66	
67	  private async consultWithCostLock(input: ClaudeConsultInput): Promise<ConsultResult> {
68	    if (!input.sessionId) {
69	      const topicLockKey = `${input.projectId}:${normalizeTopicKey(input.topicHint)}`;
70	      return this.locks.withLock(topicLockKey, async () => {
71	        const costLimit = this.checkAllConsultLimits(input.projectId);
72	        if (costLimit) {
73	          return costLimit;
74	        }
75	        const route = await this.resolveRoute(input);
76	        if ("error" in route) {
77	          return route;
78	        }
79	        return this.invokeWithRouteLock(input, route);
80	      });
81	    }
82	
83	    const explicitLockKey = `${input.projectId}:${normalizeTopicKey(input.topicHint)}`;
84	    return this.locks.withLock(explicitLockKey, async () => {
85	      const costLimit = this.checkAllConsultLimits(input.projectId);
86	      if (costLimit) {
87	        return costLimit;
88	      }
89	      const route = await this.resolveRoute(input);
90	      if ("error" in route) {
91	        return route;
92	      }
93	      return this.invokeWithRouteLock(input, route);
94	    });
95	  }
96	
97	  private async invokeWithRouteLock(input: ClaudeConsultInput, route: RouteResolution): Promise<ConsultResult> {
98	    if (!route.selectedSession) {
99	      return this.invokeClaude(input, route);
100	    }
101	
102	    return this.locks.withLock(route.selectedSession.claude_session_id, async () => {
103	      const freshRoute = await this.resolveRoute(input);
104	      if ("error" in freshRoute) {
105	        return freshRoute;
106	      }
107	      if (
108	        freshRoute.selectedSession &&
109	        freshRoute.selectedSession.claude_session_id !== route.selectedSession?.claude_session_id
110	      ) {
111	        return this.invokeWithRouteLock(input, freshRoute);
112	      }
113	      return this.invokeClaude(input, freshRoute);
114	    });
115	  }
116	
117	  private async invokeClaude(input: ClaudeConsultInput, route: RouteResolution): Promise<ConsultResult> {
118	    const context = route.bootstrapContext ?? buildSessionContext(route.selectedView);
119	    const prompt = buildConsultPrompt({
120	      projectId: input.projectId,
121	      topicHint: input.topicHint,
122	      trigger: input.trigger,
123	      task: input.task,
124	      relevantCode: input.relevantCode,
125	      question: input.question,
126	      context
127	    });
128	
129	    const estimatedTokens = estimateTokens(prompt);
130	    if (estimatedTokens > this.runtime.config.limits.maxTokensPerConsult) {
131	      this.runtime.db.logEvent({
132	        sessionId: route.selectedSession?.id ?? null,
133	        projectId: input.projectId,
134	        eventType: "cost_limit_exceeded",
135	        question: input.question,
136	        tokensIn: estimatedTokens,
137	        error: "max_tokens_per_consult"
138	      });
139	      return errorPayload(
140	        ERROR_CODES.COST_LIMIT_EXCEEDED,
141	        "Claude consult limit exceeded: max_tokens_per_consult. Parent agent should continue without Claude escalation or retry later.",
142	        { limit: "max_tokens_per_consult", value: this.runtime.config.limits.maxTokensPerConsult }
143	      );
144	    }
145	
146	    const startMs = this.runtime.clock.nowMillis();
147	    try {
148	      const claudeResponse = await this.runtime.claude.runPrompt(prompt, route.selectedSession?.claude_session_id);
149	      const durationMs = this.runtime.clock.nowMillis() - startMs;
150	      const sessionId =
151	        route.selectedSession?.id ??
152	        createInternalSessionId();
153	
154	      if (!route.selectedSession) {
155	        this.runtime.db.createSession({
156	          id: sessionId,
157	          projectId: input.projectId,
158	          claudeSessionId: claudeResponse.sessionId,
159	          topic: input.topicHint,
160	          dormantAfterDays: this.runtime.config.lifecycle.defaultDormantAfterDays,
161	          archiveAfterDays: this.runtime.config.lifecycle.defaultArchiveAfterDays
162	        });
163	      } else {
164	        this.runtime.db.updateSessionLastUsed(route.selectedSession.id);
165	      }
166	
167	      const rawResponsePath = this.writeRawResponse(sessionId, claudeResponse.result);
168	      const parsedUpdate = this.tryParseUpdate(sessionId, input.projectId, claudeResponse.result, rawResponsePath);
169	      if (parsedUpdate.update) {
170	        this.runtime.db.applySessionUpdate(sessionId, parsedUpdate.update);
171	      }
172	      const tokensIn = claudeResponse.tokensIn ?? estimatedTokens;
173	      const tokensOut = claudeResponse.tokensOut ?? estimateTokens(parsedUpdate.answer);
174	      const tokenAnomaly = this.detectTokenAnomaly(estimatedTokens, tokensIn);
175	      if (tokenAnomaly) {
176	        this.runtime.db.logEvent({
177	          sessionId,
178	          projectId: input.projectId,
179	          eventType: "token_anomaly",
180	          question: input.question,
181	          tokensIn,
182	          tokensOut,
183	          durationMs,
184	          error: `actual_tokens_in=${tokensIn} estimated_tokens=${estimatedTokens} ratio=${tokenAnomaly.ratio.toFixed(2)} threshold_ratio=${tokenAnomaly.threshold_ratio} min_delta=${tokenAnomaly.min_delta}`
185	        });
186	      }
187	
188	      this.runtime.db.logEvent({
189	        sessionId,
190	        projectId: input.projectId,
191	        eventType: route.selectedSession ? "consult" : "new_session",
192	        question: input.question,
193	        answerSummary: parsedUpdate.answer.slice(0, 300),
194	        rawResponsePath,
195	        matchScore: route.matchScore,
196	        matchReason: route.matchReason,
197	        wasNewSession: !route.selectedSession,
198	        wasOrphanRecovery: route.wasOrphanRecovery,
199	        tokensIn,
200	        tokensOut,
201	        durationMs
202	      });
203	
204	      this.applyParseFailureThreshold(sessionId);
205	
206	      return {
207	        session_id: sessionId,
208	        claude_session_id: route.selectedSession?.claude_session_id ?? claudeResponse.sessionId,
209	        answer: parsedUpdate.answer,
210	        routing: {
211	          match_score: route.matchScore,
212	          match_reason: route.matchReason,
213	          was_new_session: !route.selectedSession,
214	          was_orphan_recovery: route.wasOrphanRecovery
215	        },
216	        ...(parsedUpdate.update ? { session_update: parsedUpdate.update } : {}),
217	        ...(parsedUpdate.warning ? { warning: parsedUpdate.warning } : {}),
218	        ...(tokenAnomaly ? { diagnostics: { token_anomaly: tokenAnomaly } } : {})
219	      };
220	    } catch (error: unknown) {
221	      const message = error instanceof Error ? error.message : String(error);
222	      if (route.selectedSession) {
223	        this.runtime.db.logEvent({
224	          sessionId: route.selectedSession.id,
225	          projectId: input.projectId,
226	          eventType: "resume_failed",
227	          question: input.question,
228	          error: message
229	        });
230	        this.applyResumeFailureThreshold();
231	      }
232	
233	      this.runtime.db.logEvent({
234	        sessionId: route.selectedSession?.id ?? null,
235	        projectId: input.projectId,
236	        eventType: "health_check_failed",
237	        question: input.question,
238	        error: message
239	      });
240	      const diagnosis = diagnoseClaudeFailure(message);
241	      return errorPayload(ERROR_CODES.CLAUDE_INVOCATION_FAILED, SPEC_ERROR_MESSAGES[ERROR_CODES.CLAUDE_INVOCATION_FAILED], {
242	        reason: diagnosis.reason,
243	        category: diagnosis.category,
244	        operator_action: diagnosis.operator_action
245	      });
246	    }
247	  }
248	
249	  private async resolveRoute(input: ClaudeConsultInput): Promise<RouteResolution | ErrorPayload> {
250	    if (input.sessionId) {
251	      const session = this.runtime.db.getSession(input.sessionId);
252	      if (!session) {
253	        return errorPayload(ERROR_CODES.SESSION_NOT_FOUND, SPEC_ERROR_MESSAGES[ERROR_CODES.SESSION_NOT_FOUND]);
254	      }
255	      if (session.project_id !== input.projectId) {
256	        return errorPayload(ERROR_CODES.PROJECT_MISMATCH, SPEC_ERROR_MESSAGES[ERROR_CODES.PROJECT_MISMATCH]);
257	      }
258	      if (session.status === "orphaned" || session.status === "archived") {
259	        const oldView = this.runtime.db.getSessionView(session.id);
260	        const reason = session.status === "archived" ? "archived_resume" : "orphaned";
261	        return {
262	          selectedSession: null,
263	          selectedView: null,
264	          bootstrapContext: oldView ? buildBootstrapContext(oldView, reason) : undefined,
265	          matchScore: 0,
266	          matchReason: `Selected session was ${session.status}; creating replacement from registry context.`,
267	          wasOrphanRecovery: session.status === "orphaned"
268	        };
269	      }
270	
271	      const exists = await this.runtime.claude.sessionFileExists(session.claude_session_id);
272	      if (!exists) {
273	        const oldView = this.runtime.db.getSessionView(session.id);
274	        this.runtime.db.markSessionOrphaned(session.id);
275	        return {
276	          selectedSession: null,
277	          selectedView: null,
278	          bootstrapContext: oldView ? buildBootstrapContext(oldView, "orphaned") : undefined,
279	          matchScore: 0,
280	          matchReason: "Selected session was orphaned; creating replacement from registry context.",
281	          wasOrphanRecovery: true
282	        };
283	      }
284	
285	      return {
286	        selectedSession: session,
287	        selectedView: this.runtime.db.getSessionView(session.id),
288	        matchScore: 1,
289	        matchReason: "Direct session_id provided and project/Claude session health checks passed.",
290	        wasOrphanRecovery: false
291	      };
292	    }
293	
294	    this.runtime.db.applyLifecycle(input.projectId);
295	    const sessions = this.runtime.db.listMatchCandidates(input.projectId, false);
296	    const exactTopicSession = sessions.find((session) => normalizeTopicKey(session.topic) === normalizeTopicKey(input.topicHint));
297	    if (exactTopicSession) {
298	      const selectedSession = this.runtime.db.getSession(exactTopicSession.id);
299	      if (selectedSession) {
300	        const exists = await this.runtime.claude.sessionFileExists(selectedSession.claude_session_id);
301	        if (!exists) {
302	          const oldView = this.runtime.db.getSessionView(selectedSession.id);
303	          this.runtime.db.markSessionOrphaned(selectedSession.id);
304	          return {
305	            selectedSession: null,
306	            selectedView: null,
307	            bootstrapContext: oldView ? buildBootstrapContext(oldView, "orphaned") : undefined,
308	            matchScore: 1,
309	            matchReason: "Exact normalized topic match was orphaned; creating replacement from registry context.",
310	            wasOrphanRecovery: true
311	          };
312	        }
313	        return {
314	          selectedSession,
315	          selectedView: this.runtime.db.getSessionView(selectedSession.id),
316	          matchScore: 1,
317	          matchReason: "Exact normalized topic match within project; reusing existing session.",
318	          wasOrphanRecovery: false
319	        };
320	      }
321	    }
322	
323	    const match = findBestSessionMatch(
324	      sessions,
325	      {
326	        topicHint: input.topicHint,
327	        task: input.task,
328	        relevantCode: input.relevantCode,
329	        question: input.question
330	      },
331	      this.runtime.config.matching.thresholdUse,
332	      this.runtime.config.matching.thresholdLowConfidence
333	    );
334	
335	    if (!match.session) {
336	      const archivedBootstrap = this.findArchivedBootstrap(input);
337	      if (archivedBootstrap) {
338	        return archivedBootstrap;
339	      }
340	      return {
341	        selectedSession: null,
342	        selectedView: null,
343	        matchScore: match.score,
344	        matchReason: match.reason,
345	        wasOrphanRecovery: false
346	      };
347	    }
348	
349	    const selectedSession = this.runtime.db.getSession(match.session.id);
350	    if (selectedSession) {
351	      const exists = await this.runtime.claude.sessionFileExists(selectedSession.claude_session_id);
352	      if (!exists) {
353	        const oldView = this.runtime.db.getSessionView(selectedSession.id);
354	        this.runtime.db.markSessionOrphaned(selectedSession.id);
355	        return {
356	          selectedSession: null,
357	          selectedView: null,
358	          bootstrapContext: oldView ? buildBootstrapContext(oldView, "orphaned") : undefined,
359	          matchScore: match.score,
360	          matchReason: "Auto-routed session was orphaned; creating replacement from registry context.",
361	          wasOrphanRecovery: true
362	        };
363	      }
364	    }
365	    return {
366	      selectedSession,
367	      selectedView: selectedSession ? this.runtime.db.getSessionView(selectedSession.id) : null,
368	      matchScore: match.score,
369	      matchReason: match.lowConfidence ? `Low confidence auto-route. ${match.reason}` : match.reason,
370	      wasOrphanRecovery: false
371	    };
372	  }
373	
374	  private findArchivedBootstrap(input: ClaudeConsultInput): RouteResolution | null {
375	    const archivedSessions = this.runtime.db
376	      .listMatchCandidates(input.projectId, true)
377	      .filter((session) => session.status === "archived");
378	    const match = findBestSessionMatch(
379	      archivedSessions,
380	      {
381	        topicHint: input.topicHint,
382	        task: input.task,
383	        relevantCode: input.relevantCode,
384	        question: input.question
385	      },
386	      this.runtime.config.matching.thresholdUse,
387	      this.runtime.config.matching.thresholdLowConfidence
388	    );
389	    if (!match.session) {
390	      return null;
391	    }
392	
393	    const view = this.runtime.db.getSessionView(match.session.id);
394	    if (!view) {
395	      return null;
396	    }
397	
398	    const archiveReason =
399	      this.runtime.db.getLastArchiveReason(match.session.id) === "parse_failure_threshold"
400	        ? "parse_failure_threshold"
401	        : "archived_resume";
402	
403	    return {
404	      selectedSession: null,
405	      selectedView: null,
406	      bootstrapContext: buildBootstrapContext(view, archiveReason),
407	      matchScore: match.score,
408	      matchReason: `Archived session used as bootstrap; creating replacement. ${match.reason}`,
409	      wasOrphanRecovery: false
410	    };
411	  }
412	
413	  private checkAllConsultLimits(projectId: string): ErrorPayload | null {
414	    return (
415	      this.checkConsultLimit(projectId, "max_consults_per_hour") ??
416	      this.checkConsultLimit(projectId, "max_consults_per_day")
417	    );
418	  }
419	
420	  private checkConsultLimit(projectId: string, limitName: "max_consults_per_hour" | "max_consults_per_day"): ErrorPayload | null {
421	    const limit =
422	      limitName === "max_consults_per_hour"
423	        ? this.runtime.config.limits.maxConsultsPerHour
424	        : this.runtime.config.limits.maxConsultsPerDay;
425	    const since =
426	      limitName === "max_consults_per_hour"
427	        ? isoHoursAgo(this.runtime.clock, 1)
428	        : isoHoursAgo(this.runtime.clock, 24);
429	    const count = this.runtime.db.countConsultLikeEvents(projectId, since);
430	    if (count < limit) {
431	      return null;
432	    }
433	
434	    this.runtime.db.logEvent({
435	      projectId,
436	      eventType: "cost_limit_exceeded",
437	      error: limitName
438	    });
439	    return errorPayload(
440	      ERROR_CODES.COST_LIMIT_EXCEEDED,
441	      `Claude consult limit exceeded: ${limitName}=${limit}. Parent agent should continue without Claude escalation or retry later.`,
442	      { limit: limitName, value: limit }
443	    );
444	  }
445	
446	  private tryParseUpdate(sessionId: string, projectId: string, rawResponse: string, rawResponsePath: string): ParsedUpdateResult {
447	    try {
448	      const parsed = parseSessionUpdate(rawResponse);
449	      if (!parsed) {
450	        throw new Error("SESSION_UPDATE_JSON block missing");
451	      }
452	      return {
453	        answer: parsed.answer,
454	        update: parsed.update
455	      };
456	    } catch (error: unknown) {
457	      const message = error instanceof Error ? error.message : String(error);
458	      this.runtime.db.logEvent({
459	        sessionId,
460	        projectId,
461	        eventType: "parse_failed",
462	        rawResponsePath,
463	        error: message
464	      });
465	      return {
466	        answer: rawResponse,
467	        warning: {
468	          code: ERROR_CODES.SESSION_UPDATE_PARSE_FAILED,
469	          message: SPEC_ERROR_MESSAGES[ERROR_CODES.SESSION_UPDATE_PARSE_FAILED]
470	        }
471	      };
472	    }
473	  }
474	
475	  private applyParseFailureThreshold(sessionId: string): void {
476	    const oldestRecentConsult = this.runtime.db.oldestRecentConsultLikeEventIso(sessionId, 10);
477	    if (!oldestRecentConsult) {
478	      return;
479	    }
480	
481	    const failures = this.runtime.db.countParseFailuresSince(sessionId, oldestRecentConsult);
482	    if (failures / 10 <= 0.2) {
483	      return;
484	    }
485	
486	    const session = this.runtime.db.getSession(sessionId);
487	    if (!session || session.status === "archived") {
488	      return;
489	    }
490	
491	    this.runtime.db.logEvent({
492	      sessionId,
493	      projectId: session.project_id,
494	      eventType: "parse_failed_threshold_exceeded",
495	      error: "parse_failure_threshold"
496	    });
497	    this.runtime.db.archiveSession(sessionId, "parse_failure_threshold");
498	  }
499	
500	  private applyResumeFailureThreshold(): void {
501	    const since = isoMinutesAgo(this.runtime.clock, this.runtime.config.claude.resumeFailureWindowMinutes);
502	    const failures = this.runtime.db.countDistinctResumeFailuresSince(since);
503	    if (failures < this.runtime.config.claude.resumeFailureThreshold) {
504	      return;
505	    }
506	
507	    this.runtime.degradedMode = true;
508	    this.runtime.db.logEvent({
509	      projectId: "router",
510	      eventType: "resume_systematic_failure",
511	      error: "resume_failure_threshold"
512	    });
513	    this.runtime.db.logEvent({
514	      projectId: "router",
515	      eventType: "degraded_mode_entered",
516	      error: "resume_systematic_failure"
517	    });
518	  }
519	
520	  private writeRawResponse(sessionId: string, rawResponse: string): string {
521	    mkdirSync(this.runtime.config.storage.rawLogsDir, { recursive: true });
522	    const filePath = path.join(
523	      this.runtime.config.storage.rawLogsDir,
524	      `${sessionId}-${this.runtime.clock.nowMillis()}.txt`
525	    );
526	    writeFileSync(filePath, rawResponse, "utf8");
527	    return filePath;
528	  }
529	
530	  private detectTokenAnomaly(estimatedTokens: number, actualTokensIn: number): TokenAnomalyDiagnostic | null {
531	    const thresholdRatio = this.runtime.config.limits.tokenAnomalyRatio;
532	    const minDelta = this.runtime.config.limits.tokenAnomalyMinDelta;
533	    if (thresholdRatio <= 0) {
534	      return null;
535	    }
536	    const ratio = actualTokensIn / Math.max(estimatedTokens, 1);
537	    if (ratio <= thresholdRatio || actualTokensIn - estimatedTokens <= minDelta) {
538	      return null;
539	    }
540	    return {
541	      estimated_tokens: estimatedTokens,
542	      actual_tokens_in: actualTokensIn,
543	      ratio,
544	      threshold_ratio: thresholdRatio,
545	      min_delta: minDelta
546	    };
547	  }
548	}
549	
550	interface RouteResolution {
551	  selectedSession: SessionRecord | null;
552	  selectedView: SessionInspectView | null;
553	  bootstrapContext?: string;
554	  matchScore: number;
555	  matchReason: string;
556	  wasOrphanRecovery: boolean;
557	}
558	
559	interface ParsedUpdateResult {
560	  answer: string;
561	  update?: SessionUpdateData;
562	  warning?: {
563	    code: typeof ERROR_CODES.SESSION_UPDATE_PARSE_FAILED;
564	    message: string;
565	  };
566	}
567	
568	interface TokenAnomalyDiagnostic {
569	  estimated_tokens: number;
570	  actual_tokens_in: number;
571	  ratio: number;
572	  threshold_ratio: number;
573	  min_delta: number;
574	}
575	
576	function estimateTokens(text: string): number {
577	  return Math.ceil(text.length / 4);
578	}
